import{p as a,bh as n,I as i,U as e}from"./chunks/framework.BpabEsSf.js";const k=JSON.parse('{"title":"Спецификация формата резервного копирования WebDAV","description":"","frontmatter":{"title":"Спецификация формата резервного копирования WebDAV","date":"2026-05-01T23:00:00.000Z","permalink":"reference/webdav-backup-specification","categories":["Technical Specifications"],"tags":["WebDAV","Backup","Security"]},"headers":[],"relativePath":"ru/02.Configuration/02.Docs/01.Monica-Android-WebDAV Backup Format Specification.md","filePath":"ru/02.Configuration/02.Docs/01.Monica-Android-WebDAV Backup Format Specification.md","lastUpdated":null}'),l={name:"ru/02.Configuration/02.Docs/01.Monica-Android-WebDAV Backup Format Specification.md"};function t(p,s,o,r,c,h){return n(),i("div",null,[...s[0]||(s[0]=[e(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /ru\\02.Configuration\\02.Docs\\01.Monica-Android-WebDAV Backup Format Specification.md for this page in Markdown format</div><h1 id="📦-спецификация-формата-резервного-копирования-monica-webdav" tabindex="-1">📦 Спецификация формата резервного копирования Monica WebDAV <a class="header-anchor" href="#📦-спецификация-формата-резервного-копирования-monica-webdav" aria-label="Permalink to &quot;📦 Спецификация формата резервного копирования Monica WebDAV&quot;">​</a></h1><div class="note custom-block"><p class="title note-title custom-block-title">Аннотация</p><p>Настоящая спецификация определяет структуру архива, базовые форматы данных и протоколы шифрования, используемые локальным хранилищем <code>Monica</code> во время автоматического резервного копирования WebDAV и передачи данных. Разработанный фреймворк обеспечивает надежные <strong>возможности кроссплатформенного парсинга</strong> наряду с <strong>бескомпромиссным уровнем конфиденциальности и безопасности</strong>.</p></div><hr><h2 id="_1-обзор" tabindex="-1">1. Обзор <a class="header-anchor" href="#_1-обзор" aria-label="Permalink to &quot;1. Обзор&quot;">​</a></h2><p>Механизм резервного копирования WebDAV в Monica упаковывает основные данные пользователя в стандартный ZIP-архив (имеет расширение <code>.zip</code> без шифрования и <code>.enc.zip</code> при включении высокопрочного шифрования резервных копий).</p><p>Вместо традиционных избыточных прямых двоичных экспортов баз данных, архив резервной копии использует слабосвязанную архитектуру, состоящую из <strong>основных данных <code>.json</code></strong>, <strong>сводных таблиц <code>.csv</code></strong> и <strong>медиаресурсов (изображений)</strong>. Это гарантирует упрощенный аудит данных и высокоточную логику восстановления на любых платформах в будущем.</p><hr><h2 id="_2-структура-каталогов-архивного-пакета" tabindex="-1">2. Структура каталогов архивного пакета <a class="header-anchor" href="#_2-структура-каталогов-архивного-пакета" aria-label="Permalink to &quot;2. Структура каталогов архивного пакета&quot;">​</a></h2><p>Дерево структуры стандартного ZIP-архива резервной копии после распаковки выглядит следующим образом:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/ (Корневой каталог)</span></span>
<span class="line"><span>├── passwords/                  # Записи паролей (высокосвязное раздельное хранение)</span></span>
<span class="line"><span>│   ├── password_1_1700000.json</span></span>
<span class="line"><span>│   └── password_2_1700001.json</span></span>
<span class="line"><span>├── notes/                      # Защищенные заметки</span></span>
<span class="line"><span>│   └── note_1_1700005.json</span></span>
<span class="line"><span>├── cards/                      # Кошелек банковских карт</span></span>
<span class="line"><span>│   └── card_1_1700010.json</span></span>
<span class="line"><span>├── otp/                        # Сиды аутентификатора 2FA</span></span>
<span class="line"><span>│   └── otp_1_1700015.json</span></span>
<span class="line"><span>├── images/                     # Зашифрованные бинарные медиавложения</span></span>
<span class="line"><span>│   ├── attachment_blob_a.bin</span></span>
<span class="line"><span>│   └── attachment_blob_b.bin</span></span>
<span class="line"><span>├── summary.csv                 # Таблица быстрого индекса (для генерации превью списков)</span></span>
<span class="line"><span>└── metadata.json               # Метаданные архива (версия приложения, штамп времени, соль)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><hr><h2 id="_3-спецификация-схемы-основных-полеи-данных-json" tabindex="-1">3. Спецификация схемы основных полей данных (JSON) <a class="header-anchor" href="#_3-спецификация-схемы-основных-полеи-данных-json" aria-label="Permalink to &quot;3. Спецификация схемы основных полей данных (JSON)&quot;">​</a></h2><p>Каждая сущность внутри каталогов сериализуется в строго типизированный документ JSON. Ниже приведен пример схемы для объекта пароля (<code>passwords/password_*.json</code>):</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1700000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;title&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;GitHub Account&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;username&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mrmiaomrzh&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;password&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;EncryptedBase64String...&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;websiteUrl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;[https://github.com](https://github.com)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;notes&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Личный аккаунт разработчика&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;ssoRefEntryId&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1700002</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;categoryId&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">12</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;totpSecretId&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1700015</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;lastModifiedTime&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1776289200000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;isPinned&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><h3 id="описание-критических-полеи-связеи" tabindex="-1">Описание критических полей связей: <a class="header-anchor" href="#описание-критических-полеи-связеи" aria-label="Permalink to &quot;Описание критических полей связей:&quot;">​</a></h3><ul><li><code>ssoRefEntryId</code>: Внешний ключ связи (ID ссылки стороннего входа), указывающий на другую запись учетных данных для реализации механики сквозной авторизации.</li><li><code>totpSecretId</code>: Идентификатор ассоциации с объектом в каталоге <code>otp/</code> для синхронного вывода кодов 2FA на карточке пароля.</li></ul><hr><h2 id="_4-криптографическии-слои-двоичного-потока-monica-enc-v1" tabindex="-1">4. Криптографический слой двоичного потока <code>MONICA_ENC_V1</code> <a class="header-anchor" href="#_4-криптографическии-слои-двоичного-потока-monica-enc-v1" aria-label="Permalink to &quot;4. Криптографический слой двоичного потока \`MONICA_ENC_V1\`&quot;">​</a></h2><p>Когда пользователь активирует сквозное шифрование резервных копий, ZIP-архив перед передачей по сети обрабатывается специализированным криптографическим модулем:</p><ol><li><strong>Алгоритм шифрования</strong>: Используется режим <strong>AES-256-GCM</strong> (Advanced Encryption Standard в режиме Галуа/счетчика) с аутентификацией данных, что предотвращает не только чтение, но и любые попытки незаметного изменения бит файла на облачном сервере.</li><li><strong>Дизайн заголовка (Header)</strong>: В начало бинарного файла резервной копии принудительно внедряется блок заголовка со следующей сигнатурой структуры:</li></ol><ul><li><code>MONICA_ENC_V1</code> (Магические байты — маркер версии генерации формата).</li><li>Высокоэнтропийная случайная соль (<code>Salt</code>, 16 байт) для PBKDF2.</li><li>Случайный вектор инициализации (<code>IV</code>, 12 байт).</li></ul><hr><h2 id="_5-логика-восстановления-на-устроиствах-и-разрешения-конфликтов-идентификаторов" tabindex="-1">5. Логика восстановления на устройствах и разрешения конфликтов идентификаторов <a class="header-anchor" href="#_5-логика-восстановления-на-устроиствах-и-разрешения-конфликтов-идентификаторов" aria-label="Permalink to &quot;5. Логика восстановления на устройствах и разрешения конфликтов идентификаторов&quot;">​</a></h2><p>Во время фазы импорта или восстановления данных из облака клиентская среда выполнения строго выполняет следующий конвейер жизненного цикла:</p><ol><li><strong>Дешифрование и валидация</strong>: Считывание заголовка <code>.enc.zip</code> ➔ Проверка целостности магических байтов ➔ Дешифрование потока через ключи, деривированные из пароля бэкапа ➔ Распаковка файлов в изолированную виртуальную песочницу в оперативной памяти.</li><li><strong>Разрешение конфликтов ID</strong>:</li></ol><ul><li>Если обнаруживается, что <code>id</code> извлекаемой JSON-записи уже существует в активной локальной базе данных устройства, движок <strong>блокирует прямую перезапись</strong> (предотвращая потерю более новых локальных данных).</li><li>Активируется резервный маршрут: для входящей записи динамически выделяется новый уникальный физический идентификатор <code>Long ID</code>, после чего она безопасно сохраняется в виде новой сущности.</li></ul><ol start="3"><li><strong>Реструктуризация графа связей (Ремонт маппинга ID)</strong>:</li></ol><ul><li>Рантайм компилирует временную карту соответствий вида <code>Old ID ➔ New ID</code>.</li><li>Система автоматически сканирует и перезаписывает параметры <code>ssoRefEntryId</code>, индикаторы парных аккаунтов и привязки TOTP, сохраняя логическую целостность графа данных без разрыва реляционных связей.</li></ul><ol start="4"><li><strong>Релокация медиаактивов</strong>:</li></ol><ul><li>Обрабатываются все бинарные записи внутри дерева директории <code>images/</code>.</li><li>Фотоснимки и документы безопасно мигрируют во внутреннюю изолированную файловую систему хост-приложения (<code>context.filesDir</code>), а соответствующие внутренние пути путей обновляются в активной базе данных заметок</li></ul>`,31)])])}const u=a(l,[["render",t]]);export{k as __pageData,u as default};
